import{_ as e,c as a,o as n,a5 as s}from"./chunks/framework.DwbewbAn.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"doc/数据库/Mysql/面试总结/sql优化规则.md","filePath":"packages/doc/src/数据库/Mysql/面试总结/sql优化规则.md","lastUpdated":1711637456000}'),i={name:"doc/数据库/Mysql/面试总结/sql优化规则.md"},p=s(`<h2 id="常见的sql优化规则" tabindex="-1">常见的SQL优化规则 <a class="header-anchor" href="#常见的sql优化规则" aria-label="Permalink to &quot;常见的SQL优化规则&quot;">​</a></h2><h3 id="_1-子查询通过join改写优化" tabindex="-1">1.子查询通过join改写优化 <a class="header-anchor" href="#_1-子查询通过join改写优化" aria-label="Permalink to &quot;1.子查询通过join改写优化&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>示例：</span></span>
<span class="line"><span>select * from student where id not in (select student_id from car)</span></span>
<span class="line"><span>改写成</span></span>
<span class="line"><span>select * from student as a left join car as b on a.id = b.student_id where b.student_id is null</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>![image-20211114164519142](/Users/xulei/Library/Application Support/typora-user-images/image-20211114164519142.png)</p><p>![image-20211114164535865](/Users/xulei/Library/Application Support/typora-user-images/image-20211114164535865.png)</p><h3 id="_2-分页limit的优化" tabindex="-1">2.分页limit的优化 <a class="header-anchor" href="#_2-分页limit的优化" aria-label="Permalink to &quot;2.分页limit的优化&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>select id,name from student order by created_at limit 10000,20</span></span>
<span class="line"><span>mysql会取出10020条记录，然后丢弃前10000条</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>优化策略1：尽量使用覆盖索引</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>Alter table student add index idx_lmtes(name,created_at)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>记录直接从覆盖索引获取，只适合字段较少的情况</p><p>优化策略2：sql改写</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>select a.i,a.name from student as a inner join (select id from student order by created_at limit 10000,20) as b on a.id=b.id</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>优化的前提是created_at有索引，先从索引获取主键，然后回表</p><p>优化策略3：使用子查询（适用于ID递增的情况，不连续也没关系）</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>select * from student where id&gt;=(select id from student limit 100000,1) limit 20;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>优化策略4：使用ID限定优化(适用于ID连续递增)</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>select * from student where id between 10000 and 10020 limit 20;</span></span>
<span class="line"><span>select * from student where id &gt;= 10001 limit 20;</span></span>
<span class="line"><span>select * from student where id in (select student_id from car where student_id != 0) limit 20;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>优化策略5：总结</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>根据业务需求，有以下三种解决方法：</span></span>
<span class="line"><span> 1）select * from sbtest1 where id &gt; #max_id# order by id limit n;</span></span>
<span class="line"><span> 适用顺序翻页的场景，每次记录上一页#max_id#带入下一次查询中。</span></span>
<span class="line"><span> 2）select * from sbtest1 as a inner join (select id from sbtest1 order by id limit m, n) as b</span></span>
<span class="line"><span> on a.id = b.id order by a.id;</span></span>
<span class="line"><span> 适用只按照id进行分页，无Where条件。</span></span>
<span class="line"><span> 3）select * from sbtest1 as a inner join (select id from sbtest1where col=xxxx order by id limit m, n) as b</span></span>
<span class="line"><span> on a.id = b.id order by a.id;</span></span>
<span class="line"><span> 适用于带Where条件，同时按照ID顺序分页。此时，需要在Where条件上创建二级索引。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h3 id="_3-insert-into优化" tabindex="-1">3.insert into优化 <a class="header-anchor" href="#_3-insert-into优化" aria-label="Permalink to &quot;3.insert into优化&quot;">​</a></h3><p>优化策略1：使用批量insert, insert into student values(1,2,3),(4,5,6)...</p><p>优化策略2：使用load data infile从文本进行导入，通常比insert快20倍</p><h3 id="_4-and和or优化" tabindex="-1">4.and和or优化 <a class="header-anchor" href="#_4-and和or优化" aria-label="Permalink to &quot;4.and和or优化&quot;">​</a></h3><p>优化策略1：and组合条件创建复合索引</p><p>优化策略2：or前后字段都要创建索引；or被处理为union，相当于2个单独条件的查询</p><h3 id="_5-join优化" tabindex="-1">5.Join优化 <a class="header-anchor" href="#_5-join优化" aria-label="Permalink to &quot;5.Join优化&quot;">​</a></h3><h4 id="一-nested-loop-join" tabindex="-1">一.Nested-Loop Join <a class="header-anchor" href="#一-nested-loop-join" aria-label="Permalink to &quot;一.Nested-Loop Join&quot;">​</a></h4><p>在Mysql中，使用Nested-Loop Join的算法思想去优化join，Nested-Loop Join翻译成中文则是“嵌套循环连接”。</p><p>举个例子： select * from t1 inner join t2 on t1.id=t2.tid （1）t1称为外层表，也可称为驱动表。 （2）t2称为内层表，也可称为被驱动表。</p><p>在Mysql的实现中，Nested-Loop Join有3种实现的算法：</p><p>Simple Nested-Loop Join：SNLJ，简单嵌套循环连接 Index Nested-Loop Join：INLJ，索引嵌套循环连接 Block Nested-Loop Join：BNLJ，缓存块嵌套循环连接 在选择Join算法时，会有优先级，理论上会优先判断能否使用INLJ、BNLJ： Index Nested-LoopJoin &gt; Block Nested-Loop Join &gt; Simple Nested-Loop Join</p><h4 id="二-simple-nested-loop" tabindex="-1">二.Simple Nested-Loop <a class="header-anchor" href="#二-simple-nested-loop" aria-label="Permalink to &quot;二.Simple Nested-Loop&quot;">​</a></h4><p>简单嵌套循环连接实际上就是简单粗暴的嵌套循环，如果table1有1万条数据，table2有1万条数据，那么数据比较的次数=1万 * 1万 =1亿次，这种查询效率会非常慢。 所以Mysql继续优化，然后衍生出Index Nested-LoopJoin、Block Nested-Loop Join两种NLJ算法。在执行join查询时mysql会根据情况选择两种之一进行join查询。</p><h4 id="三-index-nested-loopjoin-减少内层表数据的匹配次数" tabindex="-1">三.Index Nested-LoopJoin（减少内层表数据的匹配次数） <a class="header-anchor" href="#三-index-nested-loopjoin-减少内层表数据的匹配次数" aria-label="Permalink to &quot;三.Index Nested-LoopJoin（减少内层表数据的匹配次数）&quot;">​</a></h4><p>索引嵌套循环连接是基于索引进行连接的算法，索引是基于内层表的，通过外层表匹配条件直接与内层表索引进行匹配，避免和内层表的每条记录进行比较， 从而利用索引的查询减少了对内层表的匹配次数，优势极大的提升了 join的性能： 原来的匹配次数 = 外层表行数 * 内层表行数 优化后的匹配次数= 外层表的行数 * 内层表索引的高度</p><p>使用场景：只有内层表join的列有索引时，才能用到Index Nested-LoopJoin进行连接。 由于用到索引，如果索引是辅助索引而且返回的数据还包括内层表的其他数据，则会回内层表查询数据，多了一些IO操作。</p><h4 id="四-block-nested-loop-join-减少内层表数据的循环次数" tabindex="-1">四.Block Nested-Loop Join（减少内层表数据的循环次数） <a class="header-anchor" href="#四-block-nested-loop-join-减少内层表数据的循环次数" aria-label="Permalink to &quot;四.Block Nested-Loop Join（减少内层表数据的循环次数）&quot;">​</a></h4><p>缓存块嵌套循环连接通过一次性缓存多条数据，把参与查询的列缓存到Join Buffer 里，然后拿join buffer里的数据批量与内层表的数据进行匹配，从而减少了内层循环的次数（遍历一次内层表就可以批量匹配一次Join Buffer里面的外层表数据）。 当不使用Index Nested-Loop Join的时候，默认使用Block Nested-Loop Join。 什么是Join Buffer？ （1）Join Buffer会缓存所有参与查询的列而不是只有Join的列。 （2）可以通过调整join_buffer_size缓存大小 （3）join_buffer_size的默认值是256K，join_buffer_size的最大值在MySQL 5.1.22版本前是4G-1，而之后的版本才能在64位操作系统下申请大于4G的Join Buffer空间。 （4）使用Block Nested-Loop Join算法需要开启优化器管理配置的optimizer_switch的设置block_nested_loop为on，默认为开启。</p><h4 id="五-bka" tabindex="-1">五.BKA <a class="header-anchor" href="#五-bka" aria-label="Permalink to &quot;五.BKA&quot;">​</a></h4><p>​ Batched Key Access Join算法的工作步骤如下：</p><ol><li><p>将外部表中相关的列放入Join Buffer中。</p></li><li><p>批量的将Key（索引键值）发送到Multi-Range Read（MRR）接口</p></li><li><p>Multi-Range Read（MRR）通过收到的Key，根据其对应的ROWID进行排序，然后再进行数据的读取操作。</p></li><li><p>返回结果集给客户端。</p></li></ol><h4 id="六-如何优化join速度" tabindex="-1">六.如何优化Join速度 <a class="header-anchor" href="#六-如何优化join速度" aria-label="Permalink to &quot;六.如何优化Join速度&quot;">​</a></h4><p>1.用小结果集驱动大结果集，减少外层循环的数据量： 如果小结果集和大结果集连接的列都是索引列，mysql在内连接时也会选择用小结果集驱动大结果集，因为索引查询的成本是比较固定的，这时候外层的循环越少，join的速度便越快。 2.为匹配的条件增加索引：争取使用INLJ，减少内层表的循环次数 3.增大join buffer size的大小：当使用BNLJ时，一次缓存的数据越多，那么外层表循环的次数就越少 4.减少不必要的字段查询： （1）当用到BNLJ时，字段越少，join buffer 所缓存的数据就越多，外层表的循环次数就越少； （2）当用到INLJ时，如果可以不回表查询，即利用到覆盖索引，则可能可以提示速度。（未经验证，只是一个推论）</p><h3 id="_6-order-by优化" tabindex="-1">6.Order By优化 <a class="header-anchor" href="#_6-order-by优化" aria-label="Permalink to &quot;6.Order By优化&quot;">​</a></h3><p>1.Order by</p><p>Order by查询的两种情况：</p><p>1）Using index，是针对查询优化器的两种行为来去区分的。Using index就是说MySQL它可以直接通过索引去返回有序</p><p>的记录，而不需要去经过额外的排序的操作；</p><p>2）Using filesort需要去做额外的排序，在某些特殊的情况下，可能还会出现临时表排序的情况。</p><p>优化目标：尽量通过索引来避免额外的排序，减少CPU资源的消耗。</p><p>·主要优化策略：</p><p>1）Where条件和Order by使用相同的索引；</p><p>2）Order by的顺序和索引顺序相同；</p><p>3）Order by 的字段同为升序或降序。</p><p>注：当Where条件中的过滤字段为覆盖索引的前缀列，而Order by字段是第二个索引列时，只有Where条件是Const匹配</p><p>时，才可以通过索引消除排序，而between…and或&gt;?、&lt;?这种Range匹配都无法避免Filesort操作。</p><p>当无法避免Filesort操作时，优化思路就是让Filesort的操作更快。</p><p>·排序算法</p><p>1）两次扫描算法。两次访问数据，第一步获取排序字段的行指针信息，在内存中排序，第二步根据行指针获取记录。</p><p>2）一次扫描算法。一次性取出满足条件的所有记录，在排序区中排序后输出结果集。是采用空间换时间的方式。</p><p>注：需要排序的字段总长度越小，越趋向于第二种扫描算法，MySQL通过max_length_for_sort_data参数的值来进行参</p><p>考选择。</p><p>·优化策略</p><p>1）适当调大max_length_for_sort_data这个参数的值，让优化器更倾向于选择第二种扫描算法；</p><p>2）只使用必要的字段，不要使用Select *的写法；</p><p>3）适当加大sort_buffer_size这个参数的值，避免磁盘排序的出现（线程参数，不要设置过大）。</p><h3 id="_7-统一字符集-建议utf8mb4" tabindex="-1">7.统一字符集，建议UTF8mb4 <a class="header-anchor" href="#_7-统一字符集-建议utf8mb4" aria-label="Permalink to &quot;7.统一字符集，建议UTF8mb4&quot;">​</a></h3><h3 id="_8-执行顺序如下" tabindex="-1">8.执行顺序如下： <a class="header-anchor" href="#_8-执行顺序如下" aria-label="Permalink to &quot;8.执行顺序如下：&quot;">​</a></h3><p>1 .FROM,（-including JOIN ）</p><ol start="2"><li><p>WHERE</p></li><li><p>GROUP BY</p></li><li><p>HAVING</p></li><li><p>WINDOW functions</p></li><li><p>SELECT</p></li><li><p>DISTINCT</p></li><li><p>UNION</p></li><li><p>ORDER BY</p></li><li><p>LIMIT and OFFSET</p></li></ol><h3 id="_9-禁止项" tabindex="-1">9.禁止项 <a class="header-anchor" href="#_9-禁止项" aria-label="Permalink to &quot;9.禁止项&quot;">​</a></h3><p>1）select *，返回无用数据，过多IO消耗，以及Schema 变更问题；</p><p>2）Insert语句指定具体字段名称，不要写成insert into t1 values(…)，道理同上；</p><p>3）禁止不带WHERE，导致全表扫描以及误操作；</p><p>4）Where条件里等号左右字段类型必须一致，否则可能 会产生隐式转换，无法利用索引；</p><p>5）索引列不要使用函数或表达式，否则无法利用索引。</p><p>如where length(name)=‘Admin’或where user_id+2=5；</p><p>6）Replace into，会导致主备不一致；</p><p>7）业务语句中带有DDL操作，特别是Truncate。</p><h3 id="_10-建议项" tabindex="-1">10.建议项 <a class="header-anchor" href="#_10-建议项" aria-label="Permalink to &quot;10.建议项&quot;">​</a></h3><p>1）减小三表以上Join；</p><p>2）用Union all 替代Union；</p><p>3）使用Join 替代子查询；</p><p>4）不要使用 like ‘%abc%’，可以使用 like ‘abc%’；</p><p>5）Order by /distinct /group by 都可以利用索引有序性；</p><p>6）减少使用event/存储过程，通过业务逻辑实现；</p><p>7）减小where in() 条件数据量；</p><p>8）减少过于复杂的查询和拼串写法。</p>`,88),t=[p];function l(o,r,d,c,b,h){return n(),a("div",null,t)}const _=e(i,[["render",l]]);export{m as __pageData,_ as default};
